import { calculateLegendSizeBasedOnRatio } from './calculate-legend-size-based-on-ratio.js';
import { calculateLegendSizeForAutoRatio } from './calculate-legend-size-for-auto-ratio.js';
import type { Orientation } from '../../../../../core/types/orientation.js';
import type { LegendRatio } from '../../../types/legend.js';
import type { ChartLayoutLegendSizes } from '../types/chart-layout.js';

export const calculateLegendSize = (
  orientation: Orientation,
  containerWidth: number,
  containerHeight: number,
  ratio: LegendRatio,
  ratioBoundaries: ChartLayoutLegendSizes,
  candidateSizes?: number,
) =>
  ratio === 'auto'
    ? calculateLegendSizeForAutoRatio(
        orientation,
        containerWidth,
        containerHeight,
        ratioBoundaries,
        candidateSizes,
      )
    : calculateLegendSizeBasedOnRatio(
        orientation,
        containerWidth,
        containerHeight,
        ratio,
      );
